using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
const int N=10010;
ll dp[N][N];
int a,b,n;
void solve()
{
	cin>>a>>b>>n;
	FOR(i,1,n)
	{
		int y,x;
		cin>>y>>x;
		dp[x][y]=-1;
	}
	if(dp[1][1]==-1||dp[b][a]==-1)
	{
		cout<<0;
		return;
	}
	dp[1][1]=1;
	FOR(i,1,b)
	{
		FOR(j,1,a)
		{
			if(dp[i][j]==-1) continue;
			if(i==1&&j==1) continue;
			else if(dp[i][j-1]==-1&&dp[i-1][j]==-1) dp[i][j]=-1;
			else if(i==1||dp[i-1][j]==-1) dp[i][j]=dp[i][j-1];
			else if(j==1||dp[i][j-1]==-1) dp[i][j]=dp[i-1][j];
			else dp[i][j]=dp[i-1][j]+dp[i][j-1];
		}
	}
	cout<<dp[b][a];
}
signed main()
{
	solve();
	return 0;
}
